    /// <summary>
    ///  API 結果コード。
    ///
    ///  状態変更系（`set_*`, `destroy`, `unload`）の戻り値。
    ///  値は安定で、追加は末尾のみとする。
    /// </summary>
    internal enum NeziaResult : int
    {
        /// <summary>
        ///  成功。
        /// </summary>
        Ok = 0,
        /// <summary>
        ///  引数が NULL だった。
        /// </summary>
        NullPointer = -1,
        /// <summary>
        ///  ハンドル（`EntityId` / `BufferId`）が無効。
        /// </summary>
        InvalidHandle = -2,
        /// <summary>
        ///  コマンドキューが満杯で発行できなかった。
        /// </summary>
        QueueFull = -3,
        /// <summary>
        ///  I/O エラー（ファイル読込失敗等）。
        /// </summary>
        IoError = -4,
        /// <summary>
        ///  オーディオデコード失敗。
        /// </summary>
        DecodeError = -5,
        /// <summary>
        ///  バス循環参照を検出した。
        /// </summary>
        BusLoopDetected = -6,
        /// <summary>
        ///  引数が範囲外（NaN, 容量超過 等）。
        /// </summary>
        InvalidArgument = -7,
        /// <summary>
        ///  パニックを `catch_unwind` で捕捉した。
        /// </summary>
        Panic = -100,
        /// <summary>
        ///  その他内部エラー。
        /// </summary>
        InternalError = -101,
    }

    /// <summary>
    ///  距離減衰モデル。`core::AttenuationModel` の ABI ミラー。
    /// </summary>
    internal enum NeziaAttenuationModel : uint
    {
        None = 0,
        Linear = 1,
        InverseDistance = 2,
        Exponential = 3,
        /// <summary>
        ///  Custom Attenuation Curve (Phase 3-1)。
        ///  `nezia_source_set_attenuation_curve` で割り当てた curve を距離→ゲイン変換に使う。
        ///  curve 未設定または curve 破棄済みの場合は silent (gain=0) フォールバックする。
        /// </summary>
        Custom = 4,
    }

    /// <summary>
    ///  エフェクト種別 (`core::EffectKind` の ABI ミラー)。
    /// </summary>
    internal enum NeziaEffectKind : byte
    {
        Lpf = 0,
        Hpf = 1,
        Reverb = 2,
        Compressor = 3,
        /// <summary>
        ///  Phase 3-5: Parametric / Peaking EQ。1 effect = 1 band。
        /// </summary>
        PeakingEq = 4,
    }

    /// <summary>
    ///  エフェクト挿入位置 (`core::EffectPosition` の ABI ミラー)。
    ///  Bus: 0=Pre-Fader, 1=Post-Fader / Source: 0=Pre-Spatial, 1=Post-Spatial
    /// </summary>
    internal enum NeziaEffectPosition : byte
    {
        Pre = 0,
        Post = 1,
    }

    /// <summary>
    ///  エフェクト対象種別。`bus_or_source` の解釈を切り替える。
    /// </summary>
    internal enum NeziaEffectTargetKind : byte
    {
        Bus = 0,
        Source = 1,
    }

    /// <summary>
    ///  Send のタップ位置 (`core::SendPosition` の ABI ミラー)。
    ///  Pre = Fader 適用前で tap (本線 mute / gain 0 でも流れる)。
    ///  Post = Fader 適用後で tap (本線 mute なら Send もゼロ)。
    /// </summary>
    internal enum NeziaSendPosition : byte
    {
        Pre = 0,
        Post = 1,
    }


